        THIS_NEW_WEAPON_THE_WAS_DEVELOPED_AS_A                                = 7383,  -- This new weapon, the %, was developed as a countermeasure for serious situations such as this, kupo. It has been designed with the ability to absorb malicious auras emitted by enemies.
        WE_WANT_YOU_TO_USE_IT_TO_ABSORB                                       = 7384,  -- We want you to use it to absorb malice from those wacky samurai wannabes, and then plant this % near where they fall. By doing so, you can further weaken the insidious individuals inside the armor, kupo!
