        BUT_THANKS_TO_ALL_YOU_COURAGEOUS_ADVENTURERS_THE                      = 7392,  -- But thanks to all you courageous adventurers, the MHMU is safe and sound, kupo!
        WE_NEED_YOUR_HELP_TO_CLEAR_THE_LAND                                   = 7393,  -- We need your help to clear the land of the malice-emitting menace, kupo!
        YOU_HAVE_EQUIPPED_GREAT_NOW_HOLD_STILL_WHILE                          = 7394,  -- You have % equipped! Great! Now, hold still while I cast miraculously marvelous moogle magic on it, kupo.
