        KUPOPOPO_THIS_IS_TERRIBLE_SOME_SNEAKY_SCOUNDRELS_HAVE                 = 7752,  -- Kupopopo`! This is terrible! Some sneaky scoundrels have swiped the armor we brought in for the Feast of Swords...again, kupo!
        AS_YOU_PROBABLY_ALREADY_KNOW_THE_VILLAINS_WEARING                     = 7753,  -- As you probably already know, the villains wearing the armor are invulnerable to normal weapons! And as if that wasn't enough, they're surrounded by a powerful aura that prevents them from being attacked at all, kupo!
        BUT_NEVER_FEAR_OUR_TOP_MOOGLE_RESEARCHERS_HAVE                        = 7754,  -- But never fear! Our top moogle researchers have created weapons that can injure these armor-thieving hooligans--the wondrous % and the marvelous %, kupo!
        THE_NOMAD_MOOGLES_HAVE_ALSO_DEVELOPED_A_MAGIC                         = 7755,  -- The nomad moogles have also developed a magic that will annul that anti-attack aura, so be sure to pay them a visit while wearing the weapon before you engage the enemy, kupo.
        BUT_BE_WARNED_THIS_MAGIC_HAS_THE_SIDE_2                               = 7756,  -- But be warned--this magic has the side effect of preventing you from attacking any other monster for three whole Vana'dielian days, kupo!
        AND_THAT_S_NOT_ALL_THIS_TIME_WE                                       = 7757,  -- And that's not all! This time we want to make sure that the wretched thieves have a hard time coming back, kupo!
        YOU_SEE_EVEN_IF_YOU_TAKE_ONE_OF                                       = 7758,  -- You see, even if you take one of them down, the power of the armor will slowly restore his health, and before you know it, the scoundrel will be back up to full health!
        THAT_S_WHY_WE_WANT_YOU_TO_PLANT                                       = 7759,  -- That's why we want you to plant (trade) your % or % into the ground near a fallen fiend. It will create a ward that should slow the equipment's regenerative properties, making it easier for you to defeat them again and again, kupo!
        JUST_REMEMBER_THAT_THE_FURTHER_AWAY_YOU_TRAVEL                        = 7760,  -- Just remember that the further away you travel from the ward, the weaker it becomes. We recommend staying in the same area for best results.
        ALRIGHT_HERE_S_YOUR_NOW_YOU_RE_READY                                  = 7761,  -- Alright. Here's your %. Now you're ready to do battle, kupo!
        OH_AND_YOU_LL_FIND_THAT_THE_PRIZES                                    = 7762,  -- Oh, and you'll find that the prizes we have for you this time are even better than the last ones. You might even be one of the lucky adventurers who wins a spiffy, new... Ah, you'll just have to see it to believe it, kupo!
        NOW_IF_YOU_WANT_TO_CROSS_SWORDS_WITH                                  = 7763,  -- Now, if you want to cross swords with the invincible interlopers, equip % or % and talk to a nomad moogle, kupo!
        VANA_DIEL_IS_UNDER_ATTACK_BY_VILLAINS_IN_3                            = 7764,  -- Vana'diel is under attack by villains in our stolen samurai armor! Help the moogles in each nation defeat this menace, kupo!
        WE_VE_MIXED_UP_SOME_MOOGLE_MAGIC_TO_3                                 = 7765,  -- We've mixed up some moogle magic to crack that aura, but you'll need to equip a special weapon to even cause a scratch, kupo! Equip, I tell you! Equiiiiiip!
